import { useState, useEffect, useCallback, useMemo, useRef } from "react";

export function useTurnLogic({
  gameSession,
  visibilityMap,
  onNotify,
  trapsLogic,
  heroStatsLogic,
  hooksPathfinding,
  combatLogic,
  mapInteractionLogic,
  visibilityCalc,
  sessionManager
}) {
  const [turnPhase, setTurnPhase] = useState({ HasMoved: false, HasPerformedAction: false, IsTurnFinished: false });
  const [movementPoints, setMovementPoints] = useState(null);
  const [hoveredPath, setHoveredPath] = useState([]);
  const [hoveredPathVariant, setHoveredPathVariant] = useState(null);
  const [canAttack, setCanAttack] = useState(false);
  const [attacksPerformed, setAttacksPerformed] = useState(0);
  const [isMoving, setIsMoving] = useState(false);
  const [isMovingStarted, setIsMovingStarted] = useState(false);
  const [canOpenDoor, setCanOpenDoor] = useState(null);
  const [activePath, setActivePath] = useState([]);

  const previousActiveTurnKey = useRef(null);

  const checkMissionObjective = useCallback(() => {
    const header = gameSession?.currentMap?.header;
    const currentMap = gameSession?.currentMap;
    if (!header || !currentMap) return true;

    const bossObjectiveId = header.mostro_uscita > 0 ? header.mostro_uscita : null;
    const itemObjectiveId = header.oggetto_f > 0 ? header.oggetto_f : null;
    const weaponObjectiveId = header.arma_f > 0 ? header.arma_f : null;
    const treasureTarget = header.tesoro_finale;
    const hasTreasureObjective = treasureTarget && (treasureTarget.x !== 0 || treasureTarget.y !== 0);

    if (!bossObjectiveId && !itemObjectiveId && !weaponObjectiveId && !hasTreasureObjective) return true;

    if (bossObjectiveId) {
      const bossAlive = gameSession.monsters?.some(m => m.monster?.id === bossObjectiveId);
      const bossHiddenButUnspawned = currentMap.grid?.some(c => c.mostab?.mos && c.mostab?.mosid === bossObjectiveId && !gameSession.spawnedLocations?.includes(`${c.x},${c.y}`));
      if (bossAlive || bossHiddenButUnspawned) return false;
    }

    if (hasTreasureObjective) {
      const targetCell = currentMap.grid?.find(c => c.x === treasureTarget.x && c.y === treasureTarget.y);
      if (targetCell && (targetCell.tes?.mon > 0 || targetCell.tes?.ogg > 0 || targetCell.tes?.arma > 0 || targetCell.tes?.trp > 0)) {
        return false;
      }
    }

    if (itemObjectiveId) {
      const itemStillOnMap = currentMap.grid?.some(c => c.tes?.ogg === itemObjectiveId);
      const itemOwned = gameSession.heroes?.some(h => h.inventory?.includes(itemObjectiveId));
      if (itemStillOnMap || !itemOwned) return false;
    }

    if (weaponObjectiveId) {
      const weaponStillOnMap = currentMap.grid?.some(c => c.tes?.arma === weaponObjectiveId);
      const weaponOwned = gameSession.heroes?.some(h => h.equipment?.includes(weaponObjectiveId));
      if (weaponStillOnMap || !weaponOwned) return false;
    }

    return true;
  }, [gameSession]);

  const isMissionObjectiveCompleted = useMemo(() => checkMissionObjective(), [checkMissionObjective]);

  const canMeleeAcrossCells = useCallback((fromX, fromY, toX, toY) => {
    const fromCell = visibilityMap?.data?.find(c => c.x === fromX && c.y === fromY);
    const toCell = visibilityMap?.data?.find(c => c.x === toX && c.y === toY);
    if (!fromCell || !toCell) return true;
    if (fromCell.valo === toCell.valo) return true;

    const openedDoors = gameSession?.openedDoors || [];
    return openedDoors.includes(`${fromX},${fromY}`) || openedDoors.includes(`${toX},${toY}`);
  }, [visibilityMap, gameSession?.openedDoors]);

  const endTurn = useCallback((force = false) => {
    if (isMoving && !force) return;

    const currentHero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
    if (currentHero) {
      if (currentHero.activeStatus?.includes("InvisiblePassage")) {
        onNotify("L'effetto di Passaggio Invisibile svanisce.");
      }
      if (currentHero.activeStatus?.includes("FoggyMist")) {
        onNotify("L'effetto di Nebbia Caliginosa svanisce.");
      }
    }

    let nextTurn = gameSession?.currentTurn || 1;
    let nextHero = null;
    const maxTurn = gameSession?.heroes?.length || 0;
    
    for (let i = 0; i < maxTurn; i++) {
      nextTurn++;
      nextHero = gameSession?.heroes?.find(h => h.turnOrder === nextTurn);
      if (nextHero && nextHero.currentBody > 0 && !nextHero.isEscaped) {
        break;
      }
    }

    setTurnPhase({ HasMoved: false, HasPerformedAction: false, IsTurnFinished: false });
    setMovementPoints(null);
    setActivePath([]);
    setHoveredPath([]);
    setHoveredPathVariant(null);
    setIsMoving(false);
    setIsMovingStarted(false);
    setAttacksPerformed(0);

    if (nextHero) {
      setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(nextHero.x, nextHero.y, null) || null);
    }

    if (currentHero) {
      if ((currentHero.bonusMeleeAttackQuota || 0) > 0) {
        sessionManager.clearBonusMeleeAttackQuotaForHero(currentHero.heroId);
      }
      if (currentHero.activeStatus?.includes("FoggyMist")) {
        sessionManager.advanceTurn(nextTurn, "FoggyMist");
        if (currentHero.activeStatus?.includes("InvisiblePassage")) {
          sessionManager.clearCurrentHeroStatus("InvisiblePassage");
        }
      } else if (currentHero.activeStatus?.includes("InvisiblePassage")) {
        sessionManager.advanceTurn(nextTurn, "InvisiblePassage");
      } else {
        sessionManager.advanceTurn(nextTurn, null);
      }
    } else {
      sessionManager.advanceTurn(nextTurn, null);
    }
  }, [isMoving, gameSession, onNotify, mapInteractionLogic, sessionManager]);

  const attemptExitFromCurrentCell = useCallback(() => {
    const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
    if (!hero) return false;

    const mapCell = gameSession?.currentMap?.grid?.find(c => c.x === hero.x && c.y === hero.y);
    if (!mapCell || !mapCell.fine) return false;

    if (!isMissionObjectiveCompleted) {
      const confirm = window.confirm("Vuoi ritirarti dalle scale senza completare la missione?");
      if (!confirm) {
        onNotify("Uscita annullata. Completa la missione o conferma la ritirata dalle scale.");
        return false;
      }
    }

    sessionManager.markCurrentHeroEscaped();
    setTurnPhase(prev => ({ ...prev, IsTurnFinished: true }));

    if (isMissionObjectiveCompleted) {
      onNotify(`${hero.hero?.classe} è uscito dal dungeon!`);
    } else {
      onNotify(`${hero.hero?.classe} si ritira dalle scale.`);
    }

    endTurn(true);
    return true;
  }, [gameSession, isMissionObjectiveCompleted, sessionManager, onNotify, endTurn]);

  const forceTurnExhausted = useCallback((positionOverride) => {
    setMovementPoints(0);
    setHoveredPath([]);
    setHoveredPathVariant(null);
    setActivePath([]);
    setIsMoving(false);
    setIsMovingStarted(false);
    setTurnPhase(prev => ({ ...prev, HasMoved: true, HasPerformedAction: true }));
    
    const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
    const pos = positionOverride || (hero ? { x: hero.x, y: hero.y } : null);
    if (pos) {
      setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(pos.x, pos.y, null) || null);
    }
  }, [gameSession, mapInteractionLogic]);

  const rollMovement = useCallback(() => {
    const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
    if (!hero || hero.currentBody <= 0 || hero.isEscaped) return;

    const stats = heroStatsLogic.calculateStats(hero);
    const bonusMoveDice = hero.bonusMovementDiceNextRoll || 0;
    const diceCount = Math.max(1, stats.movimento || 2) + bonusMoveDice;

    let roll = 0;
    for (let i = 0; i < diceCount; i++) {
      roll += Math.floor(Math.random() * 6) + 1;
    }

    setMovementPoints(roll);

    if (bonusMoveDice > 0) {
      sessionManager.clearBonusMovementDiceForHero(hero.heroId);
      onNotify(`Movimento: ${diceCount} dadi (include +${bonusMoveDice} dalla pozione).`);
    }
  }, [gameSession, heroStatsLogic, sessionManager, onNotify]);

  const handleBoardHover = useCallback((x, y) => {
    if (movementPoints == null || movementPoints <= 0 || isMoving) {
      setHoveredPath([]);
      setHoveredPathVariant(null);
      return;
    }

    const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
    if (!hero || hero.currentBody <= 0 || hero.isEscaped) {
      setHoveredPath([]);
      setHoveredPathVariant(null);
      return;
    }

    const path = hooksPathfinding.calculatePath(hero.x, hero.y, x, y, movementPoints, hero.heroId);
    if (path && path.length > 0) {
      const fullPath = [{ x: hero.x, y: hero.y }, ...path];
      setHoveredPath(fullPath);

      let crossings = 0;
      for (let i = 1; i < fullPath.length; i++) {
        const oldVis = visibilityMap?.data?.find(c => c.x === fullPath[i - 1].x && c.y === fullPath[i - 1].y);
        const newVis = visibilityMap?.data?.find(c => c.x === fullPath[i].x && c.y === fullPath[i].y);
        const isDoor = gameSession?.currentMap?.porte?.some(p => p.x === fullPath[i].x && p.y === fullPath[i].y) || gameSession?.openedDoors?.includes(`${fullPath[i].x},${fullPath[i].y}`);
        
        if (oldVis?.valo !== newVis?.valo && !isDoor) {
          crossings++;
        }
      }

      if (hero.activeStatus?.includes("WallPass") && crossings > 1) {
        setHoveredPathVariant("blocked-by-second-wall");
      } else {
        setHoveredPathVariant("valid");
      }
    } else {
      setHoveredPath([]);
      setHoveredPathVariant(null);
    }
  }, [movementPoints, isMoving, gameSession, hooksPathfinding, visibilityMap]);

  const handleBoardClick = useCallback((x, y) => {
    if (isMoving || movementPoints == null || movementPoints <= 0) return;

    setIsMovingStarted(true);
    const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
    if (!hero || hero.currentBody <= 0 || hero.isEscaped) return;

    let path = hoveredPath;
    let pathVariant = hoveredPathVariant;

    if (!path || path.length === 0 || path[path.length - 1].x !== x || path[path.length - 1].y !== y) {
      const calcPath = hooksPathfinding.calculatePath(hero.x, hero.y, x, y, movementPoints, hero.heroId);
      if (calcPath && calcPath.length > 0) {
        path = [{ x: hero.x, y: hero.y }, ...calcPath];
        pathVariant = "valid";
      }
    }

    if (path && path.length > 1 && path[path.length - 1].x === x && path[path.length - 1].y === y) {
      if (pathVariant === "blocked-by-second-wall") {
        onNotify("Passapareti permette di attraversare un solo muro.");
        setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(hero.x, hero.y, null) || null);
        return;
      }
      setCanOpenDoor(null);
      setIsMoving(true);
      setActivePath([...path]);
      setHoveredPath([]);
      setHoveredPathVariant(null);
    } else {
      setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(hero.x, hero.y, null) || null);
    }
  }, [isMoving, movementPoints, gameSession, hoveredPath, hoveredPathVariant, hooksPathfinding, onNotify, mapInteractionLogic]);

  const handleMonsterClick = useCallback((monsterId) => {
    const monster = gameSession?.monsters?.find(m => m.id === monsterId);
    const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
    if (!monster || !hero || hero.currentBody <= 0 || hero.isEscaped) return;

    const stats = heroStatsLogic.calculateStats(hero);
    const dx = Math.abs(hero.x - monster.x);
    const dy = Math.abs(hero.y - monster.y);
    const dist = dx + dy;

    let isValidTarget = false;
    if (dist <= 1 && canMeleeAcrossCells(hero.x, hero.y, monster.x, monster.y)) {
      isValidTarget = true;
    } else if (dx === 1 && dy === 1 && stats.canAttackDiagonal) {
      if (visibilityCalc?.hasLineOfSight(hero.x, hero.y, monster.x, monster.y)) isValidTarget = true;
    } else if (stats.canAttackRanged) {
      if (visibilityCalc?.hasLineOfSight(hero.x, hero.y, monster.x, monster.y)) isValidTarget = true;
    }

    if (isValidTarget && !isMoving && !turnPhase.HasPerformedAction) {
      const scriptRes = sessionManager.executeMissionScripts({
        baseSession: gameSession,
        eventType: 2,
        context: { monsterTypeId: monster.monster?.id, onDeath: false },
        visibilityMap
      });
      const attackBaseSession = scriptRes?.handled && scriptRes.session ? scriptRes.session : gameSession;
      if (scriptRes?.attackBlocked) return;

      const attackDice = heroStatsLogic.calculateAttackDice(hero, monster.monster);
      let defenseDice = monster.monster?.difesa || 0;

      if (monster.monster?.nome === "Gargoyle") {
        defenseDice += 2;
        onNotify("Il Gargoyle ha una difesa di pietra! (+2 dadi)");
      }
      if (monster.activeStatus?.includes("Tempest")) {
        defenseDice = 0;
        onNotify(`${monster.monster?.nome} è travolto dalla tempesta e non può difendersi!`);
      }

      const combatResult = combatLogic.resolveCombat(attackDice, defenseDice, false);
      const newBody = monster.currentBody - combatResult.damageDealt;
      const statusesToRemove = [];

      if (monster.activeStatus?.includes("Sleep") && newBody > 0) {
        statusesToRemove.push("Sleep");
        onNotify(`${monster.monster?.nome} si è svegliato!`);
      }
      if (monster.activeStatus?.includes("Tempest")) {
        statusesToRemove.push("Tempest");
      }

      setAttacksPerformed(prev => {
        const newCount = prev + 1;
        const canDouble = heroStatsLogic.canAttackTwice(hero, monster.monster);
        const quota = hero.bonusMeleeAttackQuota || 0;
        const baseCap = canDouble ? 2 : 1;
        const attackCap = quota > 0 ? Math.max(baseCap, quota) : baseCap;

        if (newCount < attackCap) {
          if (quota > 0 && newCount < quota) {
            onNotify("Puoi attaccare ancora (effetto della pozione).");
          } else if (canDouble && newCount < 2) {
            onNotify("Doppio attacco! Puoi attaccare ancora.");
          }
        } else {
          setTurnPhase(tp => ({ ...tp, HasPerformedAction: true }));
          if (quota > 0) {
            sessionManager.clearBonusMeleeAttackQuotaForHero(hero.heroId);
          }
        }
        return newCount;
      });

      if (isMovingStarted) {
        setTurnPhase(tp => ({ ...tp, HasMoved: true }));
      }

      setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(hero.x, hero.y, null) || null);

      const isRanged = dist > 1 || (dx === 1 && dy === 1 && !stats.canAttackDiagonal);
      let consumedId = null;
      if (isRanged) {
        consumedId = heroStatsLogic.getConsumableWeaponId(hero);
        if (consumedId) {
          onNotify("Hai lanciato l'arma e l'hai persa!");
        }
      }

      sessionManager.resolveHeroAttack(monsterId, combatResult, statusesToRemove, consumedId, attackBaseSession, isRanged);

      if (newBody <= 0) {
        const afterAttackSession = {
          ...attackBaseSession,
          monsters: attackBaseSession.monsters?.filter(m => m.id !== monsterId) || []
        };
        sessionManager.executeMissionScripts({
          baseSession: afterAttackSession,
          eventType: 2,
          context: { monsterTypeId: monster.monster?.id, onDeath: true },
          visibilityMap
        });
      }
    }
  }, [
    gameSession,
    isMoving,
    turnPhase.HasPerformedAction,
    heroStatsLogic,
    visibilityCalc,
    sessionManager,
    visibilityMap,
    combatLogic,
    onNotify,
    isMovingStarted,
    mapInteractionLogic,
    canMeleeAcrossCells
  ]);

  const handleOpenDoor = useCallback(() => {
    if (canOpenDoor) {
      mapInteractionLogic?.openPassage?.(canOpenDoor.passageCell.x, canOpenDoor.passageCell.y, canOpenDoor.destination.x, canOpenDoor.destination.y);
      const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
      if (hero) {
        setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(hero.x, hero.y, null) || null);
      }
    }
  }, [canOpenDoor, mapInteractionLogic, gameSession]);

  const markActionDone = useCallback(() => {
    setTurnPhase(prev => ({ ...prev, HasPerformedAction: true, HasMoved: isMovingStarted ? true : prev.HasMoved }));
    const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
    if (hero) {
      setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(hero.x, hero.y, null) || null);
    }
  }, [isMovingStarted, gameSession, mapInteractionLogic]);

  useEffect(() => {
    if (!gameSession) return;
    const hero = gameSession.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
    if (!hero) return;

    if (turnPhase.HasPerformedAction) {
      setCanAttack(false);
    } else {
      const stats = heroStatsLogic.calculateStats(hero);
      let attackPossible = false;
      for (const monster of gameSession.monsters || []) {
        const dx = Math.abs(hero.x - monster.x);
        const dy = Math.abs(hero.y - monster.y);
        const dist = dx + dy;

        if (dist <= 1 && canMeleeAcrossCells(hero.x, hero.y, monster.x, monster.y)) {
          attackPossible = true;
          break;
        } else if (dx === 1 && dy === 1 && stats.canAttackDiagonal) {
          if (visibilityCalc?.hasLineOfSight(hero.x, hero.y, monster.x, monster.y)) {
            attackPossible = true;
            break;
          }
        } else if (stats.canAttackRanged) {
          if (visibilityCalc?.hasLineOfSight(hero.x, hero.y, monster.x, monster.y)) {
            attackPossible = true;
            break;
          }
        }
      }
      setCanAttack(attackPossible);
    }

    const visibleMonsters = gameSession.monsters?.filter(m => {
      const cell = visibilityMap?.data?.find(c => c.x === m.x && c.y === m.y);
      return cell && !cell.fog;
    }) || [];

    if (visibleMonsters.length === 0) {
      const courageRemoved = gameSession.heroes?.some(h => h.activeStatus?.includes("Courage"));
      if (courageRemoved) {
        onNotify("L'effetto di Coraggio svanisce: non ci sono più mostri in vista.");
        sessionManager.clearHeroStatusEverywhere("Courage");
      }
    }
  }, [gameSession, turnPhase.HasPerformedAction, heroStatsLogic, visibilityCalc, visibilityMap, onNotify, sessionManager, canMeleeAcrossCells]);

  useEffect(() => {
    const currentHero = gameSession?.heroes?.find(h => h.turnOrder === gameSession?.currentTurn);
    const activeTurnKey = `${gameSession?.currentTurn}-${currentHero?.heroId}`;

    if (previousActiveTurnKey.current !== activeTurnKey) {
      setTurnPhase({ HasMoved: false, HasPerformedAction: false, IsTurnFinished: false });
      setMovementPoints(null);
      setAttacksPerformed(0);
      setIsMoving(false);
      setIsMovingStarted(false);
      setActivePath([]);
      setHoveredPath([]);
      setHoveredPathVariant(null);
      
      if (currentHero) {
        setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(currentHero.x, currentHero.y, null) || null);
      }
      
      previousActiveTurnKey.current = activeTurnKey;
    }
  }, [gameSession?.currentTurn, gameSession?.heroes, mapInteractionLogic]);

  useEffect(() => {
    if (activePath.length < 2) {
      if (isMoving) {
        setIsMoving(false);
        setActivePath([]);
      }
      const exited = attemptExitFromCurrentCell();
      if (exited) return;
      
      const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
      if (hero) {
        setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(hero.x, hero.y, null) || null);
      }
      
      if (movementPoints !== null && movementPoints <= 0) {
        setTurnPhase(prev => ({ ...prev, HasMoved: true }));
      }
      return;
    }

    const timer = setTimeout(() => {
      const nextPos = activePath[1];
      const oldPos = activePath[0];
      
      setMovementPoints(prev => (prev !== null ? prev - 1 : 0));
      
      const oldVis = visibilityMap?.data?.find(c => c.x === oldPos.x && c.y === oldPos.y);
      const newVis = visibilityMap?.data?.find(c => c.x === nextPos.x && c.y === nextPos.y);
      const isDoor = gameSession?.currentMap?.porte?.some(p => p.x === nextPos.x && p.y === nextPos.y) || gameSession?.openedDoors?.includes(`${nextPos.x},${nextPos.y}`);
      
      if (oldVis?.valo !== newVis?.valo && !isDoor) {
        const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
        if (hero?.activeStatus?.includes("WallPass")) {
          sessionManager.clearCurrentHeroStatus("WallPass");
        }
      }

      const trap = gameSession?.currentMap?.grid?.find(c => c.x === nextPos.x && c.y === nextPos.y)?.trpl;
      if (trap && trap.tipo > 0 && trapsLogic?.checkTrapActivation?.(trap, nextPos.x, nextPos.y)) {
        sessionManager.resolveMovementTrap(nextPos.x, nextPos.y, trap.tipo, trap.rccadex, trap.rccadey);
        trapsLogic?.registerTriggeredTrap?.(nextPos.x, nextPos.y, trap.tipo);
        setActivePath([]);
        setTurnPhase(prev => ({ ...prev, HasMoved: true }));
        return;
      }

      sessionManager.moveCurrentHeroTo(nextPos.x, nextPos.y, gameSession);

      const roomChanged = oldVis?.valo !== newVis?.valo;
      const scriptRes1 = sessionManager.executeMissionScripts({ baseSession: gameSession, eventType: 1, visibilityMap });
      let scriptRes8 = null;
      if (roomChanged) {
        scriptRes8 = sessionManager.executeMissionScripts({ baseSession: scriptRes1?.session || gameSession, eventType: 8, visibilityMap });
      }

      const finalRes = scriptRes8 || scriptRes1;
      if (finalRes) {
        if (finalRes.movementDelta) setMovementPoints(prev => (prev !== null ? prev + finalRes.movementDelta : prev));
        if (finalRes.stopMovement) {
          setActivePath([]);
          setMovementPoints(0);
        }
        if (finalRes.forceFinishTurn) {
          forceTurnExhausted();
        }
      }

      if (!finalRes?.stopMovement && !finalRes?.forceFinishTurn) {
        setActivePath(prev => prev.slice(1));
      }
      
      const hero = gameSession?.heroes?.find(h => h.turnOrder === gameSession.currentTurn);
      if (hero) {
        setCanOpenDoor(mapInteractionLogic?.isFrontOfDoor?.(nextPos.x, nextPos.y, null) || null);
      }

    }, 300);

    return () => clearTimeout(timer);
  }, [activePath, isMoving, movementPoints, gameSession, visibilityMap, trapsLogic, sessionManager, mapInteractionLogic, attemptExitFromCurrentCell, forceTurnExhausted]);

  return {
    turnPhase,
    movementPoints,
    hoveredPath,
    hoveredPathVariant,
    isMoving,
    canOpenDoor,
    handleOpenDoor,
    rollMovement,
    handleBoardHover,
    handleBoardClick,
    handleMonsterClick,
    markActionDone,
    forceTurnExhausted,
    endTurn,
    isMissionObjectiveCompleted,
    canAttack
  };
}